  ('social-worker-moex-00051', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '肯定多元性與差異性係社會工作專業教育的核心要素，下列敘述何者錯誤？', '["服務對象的社會與文化認同交互關係中展現多元性", "否認文化差異就是一種壓迫", "應批判反思自己的文化認同", "應理解每個人都有相同的權力來詮釋自己的差異性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00052', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '充權取向的社會工作將社會工作專業角色，從「專業專家」轉化成「協同夥伴」。下列敘述何者錯誤？', '["提供更全面的專業服務", "避免服務對象養成依賴專家的文化", "避免創造不對等的階層關係", "提供一種氛圍讓服務對象得以增強自己生活品質"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00053', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作將管理相關知能納入社會工作的專業重構（professionalreconstruction）。在重視績效與責 信的前提下，下列敘述何者錯誤？', '["社會工作專業應重視實踐結果所展現的服務績效", "獲得社會工作專業社群認可之專業才能", "社會工作專業實踐需要能回應社會對責信的訴求", "從單一專業的運作轉向跨部門與跨專業的網絡合作模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00054', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '常見的危機（crisis）可區分為四種類型，「人生價值與定位的追尋所產生的適應危機」屬於下列何 種類型？', '["發展性危機", "意外性危機", "存在性危機", "環應危機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00055', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Turner（1986）認為社會工作者在實務工作中強調理論的可運用性，可能會面臨的挑戰：①不重視', '["過度強調分類", "缺乏彈性", "與人文取向為基礎的實務工作一致", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00056', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關心理暨社會學派，下列敘述何者正確？', '["主張思考決定情緒和行為，故需促進積極增強個人的正向思考模式", "主張童年經驗和潛意識決定行為，故需協助個人洞察潛意識內涵", "主張個人問題的形成，受目前內在心理與外在環境壓力互動影響", "主張個人因長期無力和掌控感喪失，故需協助個人積極運用內在資源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00057', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列敘述何者最符合認知行為理論的假設？', '["萬物的形體架構呈現無限創組的可能性", "事情本身無所謂好壞，主要是看人怎麼想", "巴西一隻蝴蝶搧動翅膀，能否在德州掀起一場龍捲風", "沒有所謂玩笑，所有玩笑都有認真的成分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
