  ('social-worker-moex-00059', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關任務中心取向的基本假定，下列敘述何者錯誤？', '["當問題變成習以為常時，人的改變驅力就會增強", "當個人意識到問題，且處於一種不平衡狀態，就會採取行動解決", "當個人陷入困境時，就會產生改變的動力", "個人的問題是來自資源或環境的不足，而非潛意識所造成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
